import{_ as e,o as r,c as t,ak as s}from"./chunks/framework.B_unCYUt.js";const _=JSON.parse('{"title":"ψ-概率论与数理统计","description":"","frontmatter":{},"headers":[],"relativePath":"Courses/概率论与数理统计.md","filePath":"Courses/概率论与数理统计.md","lastUpdated":1708868588000}'),n={name:"Courses/概率论与数理统计.md"};function h(o,a,i,l,d,p){return r(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="ψ-概率论与数理统计" tabindex="-1">ψ-概率论与数理统计 <a class="header-anchor" href="#ψ-概率论与数理统计" aria-label="Permalink to “ψ-概率论与数理统计”">​</a></h1><h1 id="课程说明" tabindex="-1">课程说明 <a class="header-anchor" href="#课程说明" aria-label="Permalink to “课程说明”">​</a></h1><h2 id="核心观点" tabindex="-1">核心观点 <a class="header-anchor" href="#核心观点" aria-label="Permalink to “核心观点”">​</a></h2><ul><li>概率论是理想模型, 统计学是实际应用.</li></ul><h2 id="核心思想" tabindex="-1">核心思想 <a class="header-anchor" href="#核心思想" aria-label="Permalink to “核心思想”">​</a></h2><p>中心极限定理</p><p>贝叶斯方程</p><p>隐马尔科夫模型</p><p>估计理论</p><p>大数定理</p><h3 id="在我看来-概率统计的核心部分共有以下六大部分-纵贯了概率论、统计以及随机过程中最核心的主线内容" tabindex="-1">在我看来，概率统计的核心部分共有以下六大部分，纵贯了概率论、统计以及随机过程中最核心的主线内容： <a class="header-anchor" href="#在我看来-概率统计的核心部分共有以下六大部分-纵贯了概率论、统计以及随机过程中最核心的主线内容" aria-label="Permalink to “在我看来，概率统计的核心部分共有以下六大部分，纵贯了概率论、统计以及随机过程中最核心的主线内容：”">​</a></h3><p><strong>第 1 部分：概率思想。</strong>我们首先从条件概率和贝叶斯方法入手，阐明条件、独立、相关等基本概念，掌握联合、边缘的计算方法，我们将一起构建起认知世界的概率思维体系。</p><p><strong>第 2 部分：随机变量。</strong>我们将重点介绍随机变量主干内容，从单一随机变量的分布过渡到多元随机变量的分析，最后重点阐述大数定理和中心极限定理，并初步接触蒙特卡洛方法，和读者一起建立重要的极限思维。</p><p><strong>第 3 部分：统计推断。</strong>这部分我们关注的是如何通过部分的样本集合推断出我们关心的总体特征，这在现实世界中非常重要。在参数估计的思想方法基础上，我们重点关注极大似然估计和贝叶斯估计这两种方法。</p><p><strong>第 4 部分：随机过程。</strong>我们将关注由一组随机变量构成的集合，即随机过程。股票的波动、语音信号、视频信号、布朗运动等都是随机过程在现实世界中的实例。我们在随机过程的基本概念之上，将重点分析马尔科夫链，梳理其由静到动的演变，探索变化的过程和不变的稳态。</p><p><strong>第 5 部分：采样理论。</strong>我们将重点关注如何获取服从目标分布的近似采样方法，从基本的接受-拒绝采样入手，逐渐深入到马尔科夫链-蒙特卡洛方法，通过动态的过程进一步深化对随机过程、随机理论以及极限思想的理解。</p><p><strong>第 6 部分：概率模型。</strong>这里我们将介绍概率图模型中的一种典型模型：隐马尔科夫模型，熟悉状态序列的概率估计和状态解码的基本方法，为后续学习的概率图模型打好基础。知识图谱如下：</p><p><img src="https://wwfyde.oss-cn-hangzhou.aliyuncs.com/images/20210426194753.jpg" alt="img"></p><p>针对上述大纲，我们花费近半年，在<strong>gitchat平台</strong>上精心推出了专栏<strong>《机器学习中的数学：概率统计》</strong>，揭示和反映了与机器学习紧密相关的概率统计核心内容。</p><h2 id="学习方法" tabindex="-1">学习方法 <a class="header-anchor" href="#学习方法" aria-label="Permalink to “学习方法”">​</a></h2><p><a href="https://www.zhihu.com/question/26668084/answer/1182647519" target="_blank" rel="noreferrer">知乎</a></p><h2 id="基础概念" tabindex="-1">基础概念 <a class="header-anchor" href="#基础概念" aria-label="Permalink to “基础概念”">​</a></h2><h4 id="集合-set" tabindex="-1">集合 - set <a class="header-anchor" href="#集合-set" aria-label="Permalink to “集合 - set”">​</a></h4><h3 id="方差" tabindex="-1">方差 - <a class="header-anchor" href="#方差" aria-label="Permalink to “方差 -”">​</a></h3><h3 id="期望" tabindex="-1">期望 - <a class="header-anchor" href="#期望" aria-label="Permalink to “期望 -”">​</a></h3><h3 id="分布" tabindex="-1">分布 - <a class="header-anchor" href="#分布" aria-label="Permalink to “分布 -”">​</a></h3>',26)])])}const m=e(n,[["render",h]]);export{_ as __pageData,m as default};
